                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  |
| INSERT INTO public."Faq" (switch, "order", question, answer, link, link_text, created_at, updated_at, id) VALUES ('1', '2', 'How large are your classes?', 'T.O.L.R. training class sizes range from private - one on one - to group classes. We keep class sizes intentionally small — typically 6 to 12 participants — so every student gets hands-on attention from the instructor. Larger groups can be accommodated for corporate or group bookings; contact us to discuss a private session.', NULL, NULL, '2026-04-02T15:47:33+00:00', '2026-05-03T10:36:07+00:00', '2a3fea1b-101b-45a6-a0cf-a348ff585084');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             |
| INSERT INTO public."Faq" (switch, "order", question, answer, link, link_text, created_at, updated_at, id) VALUES ('1', '5', 'What should I bring to class?', 'Bring a valid photo ID, comfortable clothing you can move in, and a notepad to take notes. All training materials are provided. All training props for the hands on practical training are Non Firing - Non Handgun training replicas. There are no functional firearms or live ammunition allowed in the class room or training area at any time.', NULL, NULL, '2026-04-02T15:47:34+00:00', '2026-05-03T10:25:55+00:00', '344fd3b2-01e1-4747-9276-6b3ef128facb');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               |
| INSERT INTO public."Faq" (switch, "order", question, answer, link, link_text, created_at, updated_at, id) VALUES ('1', '1', 'Do I need a permit or ID to take a firearms safety course?', 'No permit is required to enroll in our NJ Firearms Safety courses. However, per New Jersey law, a valid government-issued photo ID is required on the day of class. If you plan to apply for a Firearms Purchaser ID Card or a Permit to Purchase a Handgun after completing the course, we can walk you through exactly what documentation the NJ State Police require — just ask at check-in.', NULL, NULL, '2026-04-02T15:47:33+00:00', '2026-05-16T16:37:27.343576+00:00', '3a292625-f667-44d2-8073-2942bc8a82ea');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              |
| INSERT INTO public."Faq" (switch, "order", question, answer, link, link_text, created_at, updated_at, id) VALUES ('1', '6', 'Do you offer private or corporate group training?', 'Absolutely. We offer on-site and facility-based private sessions for individuals and businesses, security teams, schools, and community organizations throughout New Jersey. Group rates are available. Use the booking form above or call us directly to discuss your training or event needs, scheduling and pricing for your group.', NULL, NULL, '2026-04-02T15:47:34+00:00', '2026-05-03T10:40:05+00:00', '48f0c977-8029-4ead-9572-6d9017fd27e8');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       |
| INSERT INTO public."Faq" (switch, "order", question, answer, link, link_text, created_at, updated_at, id) VALUES ('1', '3', 'How long is my certification valid?', 'The training itself doesn''t expire in most cases. If you will be applying for a NJ Permit To Carry (PTC) you will have to take re-qualification training and re-qualify on the range every 2 years.', NULL, NULL, '2026-04-02T15:47:33+00:00', '2026-05-03T10:28:38+00:00', 'a888ee6d-3750-486d-939d-ab7d4fa77716');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       |
| INSERT INTO public."Faq" (switch, "order", question, answer, link, link_text, created_at, updated_at, id) VALUES ('1', '4', 'Are your courses accepted by the NJ State Police?', 'Yes. Our NJ Permit To Carry (PTC) training course satisfies the safety-training requirement for the NJ Permit To Carry requirements set out by the state and more.  Completion certificates are issued after class via email and all necessary paperwork is provided.', NULL, NULL, '2026-04-02T15:47:33+00:00', '2026-05-03T10:19:09+00:00', 'b207e4c4-8737-4ba6-8946-b397a382eae7');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        |
| INSERT INTO public."Faq" (switch, "order", question, answer, link, link_text, created_at, updated_at, id) VALUES ('1', '7', 'What is your cancellation and refund policy?', 'Cancellations made at least 72 hours before your scheduled class receive a full refund or free reschedule. Cancellations within 72 hours may be rescheduled once at no charge. No-shows forfeit their seat. If we ever need to cancel a class due to low enrollment or circumstances beyond our control, you''ll receive a full refund and priority re-enrollment.', NULL, NULL, '2026-04-02T15:47:34+00:00', '2026-05-03T10:33:33+00:00', 'ca93ddf2-27ec-4680-8e48-8b8e5e4f76c6');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                |
