| INSERT INTO public."Review" (switch, "order", name, role, text, initials, color, rating, created_at, updated_at, id) VALUES ('1', '2', 'James T.', 'NRA basic pistol student', 'After being disappointed with an intro to pistols course elsewhere, I was pleasantly surprised to see the the level of detail, hands on practice and safety emphasis here. The NRA Basic Pistol course was thorough, practical, and worth every penny.', 'JT', 'bg-amber-100 text-amber-800', '5', '2026-05-09T10:06:42+00:00', '2026-05-10T10:55:52+00:00', '0dc072be-0a1a-409d-920a-c8d13cebd125');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         