| INSERT INTO public."Review" (switch, "order", name, role, text, initials, color, rating, created_at, updated_at, id) VALUES ('0', '7', 'Joe B', 'Course attendee', 'I attended the NJ CCW (PTC) plus class. Worth the extra time an effort.  We went into great detail regarding awareness and especially keeping up proficiency and some hints on how to train safety at home as well.', 'JB', 'bg-amber-100 text-amber-800', '5', '2026-05-10T11:19:15+00:00', '2026-05-10T11:19:15+00:00', '4360adfd-b991-4dee-b9d5-7e4d419cd0f3');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        