| INSERT INTO public."Review" (switch, "order", name, role, text, initials, color, rating, created_at, updated_at, id) VALUES ('0', '5', 'Linda P.', 'Parent & Community Member', 'I took the Refuse to Be a Victim seminar with my daughter. The situational awareness skills we learned have genuinely changed how we move through the world. Invaluable.', 'LP', 'bg-rose-100 text-rose-800', '5', '2026-05-09T10:06:43+00:00', '2026-05-10T10:55:54+00:00', '5a6fc12b-c6d1-4de1-a518-fd15513787f3');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        