| INSERT INTO public."Review" (switch, "order", name, role, text, initials, color, rating, created_at, updated_at, id) VALUES ('0', '3', 'Rachel M.', 'HR Manager, Local Business', 'We brought T.O.L.R. in for a workplace CPR/AED training. The whole team was engaged the entire time. Months have gone by, they still talk about it.', 'RM', 'bg-green-100 text-green-800', '5', '2026-05-09T10:06:42+00:00', '2026-05-10T10:55:53+00:00', '62f63a39-9b31-4968-a7ec-68f3f18ef1c0');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         