| INSERT INTO public."Review" (switch, "order", name, role, text, initials, color, rating, created_at, updated_at, id) VALUES ('1', '6', 'Officer C. Torres', 'Private Security Supervisor', 'The de-escalation training was the most realistic and scenario-based I''ve attended outside of the academy. Real-world situations, real techniques, real results.', 'CT', 'bg-sky-100 text-sky-800', '5', '2026-05-09T10:06:43+00:00', '2026-05-10T10:55:54+00:00', 'c2a56b4d-65da-405a-ad64-511a83aaa031');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        |
| INSERT INTO public."Review" (switch, "order", name, role, text, initials, color, rating, created_at, updated_at, id) VALUES ('0', '1', 'Maria S.', 'South Plainfield, NJ', 'The Stop The Bleed course was eye-opening. The instructor was calm, clear, and made every skill feel achievable. I feel genuinely prepared now — not just like I sat through a class.', 'MS', 'bg-sky-100 text-sky-800', '5', '2026-05-09T10:06:42+00:00', '2026-05-16T16:38:01.540118+00:00', 'c64418b3-a563-4ba3-a39a-a78032569132');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           