| INSERT INTO public."Review" (switch, "order", name, role, text, initials, color, rating, created_at, updated_at, id) VALUES ('1', '4', 'Dave K.', 'NJ Permit to Carry Holder', 'The NJ Permit to Carry course covered everything — use of force law, safety, range qualification. I walked out confident and fully prepared for the process. Highly recommend.', 'DK', 'bg-violet-100 text-violet-800', '5', '2026-05-09T10:06:42+00:00', '2026-05-10T10:55:53+00:00', 'c913dd36-1e81-49c9-b7d5-8ecab23e1c2f');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               