| INSERT INTO public."SectionText" (id, section, field_key, field_label, field_type, value, updated_at) VALUES ('24623765-909d-4939-bfa5-1d26495d9c0d', 'hero', 'hero_paragraph', 'Body Paragraph', 'textarea', 'T.O.L.R.™ = Tools Of Last Resort. We specialize in personal firearms training from basic firearm orientation and operation to advanced defensive shooting and knife defense. Our instructors exceed NRA standards to ensure our practices are delivered at the highest quality.', '2026-07-11T19:50:47.606661+00:00');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         