| INSERT INTO public."SectionText" (id, section, field_key, field_label, field_type, value, updated_at) VALUES ('b37a237d-257e-4f88-b534-a4b715b92377', 'services', 'services_subtext', 'Description Paragraph', 'textarea', 'If you are new to firearms or a seasoned shooter looking to improve your skills, we offer a wide variety of training courses to meet your needs.', '2026-07-11T19:50:47.606661+00:00');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           